import React, { useState } from 'react';
import DragDropCanvas from './components/DragDropCanvas';
import VisualizationLibrary from './components/VisualizationLibrary';
import ExportManager from './components/ExportManager';
import DataConnections from './components/DataConnections';
import { WindowPanel, BackgroundConfig, DataConnection } from './types';
import './App.css';

const App: React.FC = () => {
  const [windows, setWindows] = useState<WindowPanel[]>([]);
  const [backgroundConfig, setBackgroundConfig] = useState<BackgroundConfig>({
    width: 1200,
    height: 800,
    color: '#ffffff'
  });
  const [dataConnections, setDataConnections] = useState<DataConnection>({
    apiConnections: [],
    globalVariables: {}
  });
  const [activeTab, setActiveTab] = useState<'builder' | 'data'>('builder');
  const [leftPanelVisible, setLeftPanelVisible] = useState<boolean>(true);
  const [rightPanelVisible, setRightPanelVisible] = useState<boolean>(true);

  const handleAddTemplate = (type: 'javascript' | 'html', template: any) => {
    const newWindow: WindowPanel = {
      id: `window-${Date.now()}`,
      title: template.name,
      type,
      content: type === 'html' ? template.code : '',
      position: { 
        x: Math.random() * 300 + 50, 
        y: Math.random() * 200 + 50 
      },
      size: { width: 400, height: 300 },
      jsCode: type === 'javascript' ? template.code : undefined
    };

    setWindows(prev => [...prev, newWindow]);
  };

  const handleWindowsChange = (newWindows: WindowPanel[]) => {
    setWindows(newWindows);
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      fontFamily: 'Arial, sans-serif'
    }}>
      {/* Header */}
      <header style={{
        padding: '15px 20px',
        backgroundColor: '#343a40',
        color: 'white',
        borderBottom: '1px solid #dee2e6'
      }}>
        <h1 style={{ 
          margin: 0, 
          fontSize: '24px',
          fontWeight: 'normal'
        }}>
          🏗️ Website Builder - Drag & Drop Visualizations
        </h1>
        <p style={{ 
          margin: '5px 0 0 0', 
          fontSize: '14px', 
          opacity: 0.8 
        }}>
          Create interactive web applications with JavaScript and HTML windows
        </p>
      </header>

      {/* Tab Navigation */}
      <div style={{
        borderBottom: '1px solid #dee2e6',
        backgroundColor: '#f8f9fa'
      }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingLeft: '20px', paddingRight: '20px' }}>
          <div style={{ display: 'flex' }}>
            <button
              onClick={() => setActiveTab('builder')}
              style={{
                padding: '12px 20px',
                backgroundColor: activeTab === 'builder' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'builder' ? '2px solid #007bff' : '2px solid transparent',
                fontSize: '14px',
                fontWeight: activeTab === 'builder' ? 'bold' : 'normal',
                color: activeTab === 'builder' ? '#007bff' : '#6c757d',
                cursor: 'pointer',
                borderRadius: '4px 4px 0 0'
              }}
            >
              🏗️ Builder
            </button>
            <button
              onClick={() => setActiveTab('data')}
              style={{
                padding: '12px 20px',
                backgroundColor: activeTab === 'data' ? '#ffffff' : 'transparent',
                border: 'none',
                borderBottom: activeTab === 'data' ? '2px solid #007bff' : '2px solid transparent',
                fontSize: '14px',
                fontWeight: activeTab === 'data' ? 'bold' : 'normal',
                color: activeTab === 'data' ? '#007bff' : '#6c757d',
                cursor: 'pointer',
                borderRadius: '4px 4px 0 0'
              }}
            >
              🔗 Data Connections
            </button>
          </div>

          {/* Panel Toggle Buttons - Only show on Builder tab */}
          {activeTab === 'builder' && (
            <div style={{ display: 'flex', gap: '8px' }}>
              <button
                onClick={() => setLeftPanelVisible(!leftPanelVisible)}
                style={{
                  padding: '6px 12px',
                  backgroundColor: leftPanelVisible ? '#007bff' : '#6c757d',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  fontSize: '12px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '4px'
                }}
                title={leftPanelVisible ? 'Hide Templates Panel' : 'Show Templates Panel'}
              >
                {leftPanelVisible ? '◀' : '▶'} Templates
              </button>
              <button
                onClick={() => setRightPanelVisible(!rightPanelVisible)}
                style={{
                  padding: '6px 12px',
                  backgroundColor: rightPanelVisible ? '#007bff' : '#6c757d',
                  color: 'white',
                  border: 'none',
                  borderRadius: '4px',
                  fontSize: '12px',
                  cursor: 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  gap: '4px'
                }}
                title={rightPanelVisible ? 'Hide Export Panel' : 'Show Export Panel'}
              >
                Export {rightPanelVisible ? '▶' : '◀'}
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Main Layout */}
      <div style={{
        flex: 1,
        display: 'flex',
        overflow: 'hidden'
      }}>
        {activeTab === 'builder' ? (
          <>
            {/* Left Sidebar - Templates */}
            {leftPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f8f9fa',
                  borderRight: '1px solid #dee2e6',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '2px 0 10px rgba(0,0,0,0.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <VisualizationLibrary onAddTemplate={handleAddTemplate} />
              </div>
            )}

            {/* Center - Canvas */}
            <div style={{ 
              flex: 1, 
              overflow: 'auto',
              minWidth: '400px'
            }}>
              <DragDropCanvas 
                windows={windows}
                onWindowsChange={handleWindowsChange}
                backgroundConfig={backgroundConfig}
                onBackgroundConfigChange={setBackgroundConfig}
                dataConnections={dataConnections}
              />
            </div>

            {/* Right Sidebar - Export */}
            {rightPanelVisible && (
              <div 
                style={{
                  width: '250px',
                  backgroundColor: '#f8f9fa',
                  borderLeft: '1px solid #dee2e6',
                  overflow: 'auto',
                  transition: 'width 0.3s ease, z-index 0s 0.3s',
                  position: 'relative',
                  zIndex: 1,
                  minWidth: '250px'
                }}
                onMouseEnter={(e) => {
                  e.currentTarget.style.width = '350px';
                  e.currentTarget.style.zIndex = '10';
                  e.currentTarget.style.boxShadow = '-2px 0 10px rgba(0,0,0,0.1)';
                }}
                onMouseLeave={(e) => {
                  e.currentTarget.style.width = '250px';
                  e.currentTarget.style.zIndex = '1';
                  e.currentTarget.style.boxShadow = 'none';
                }}
              >
                <ExportManager 
                  windows={windows} 
                  backgroundConfig={backgroundConfig}
                  onBackgroundConfigChange={setBackgroundConfig}
                  dataConnections={dataConnections}
                />
              </div>
            )}
          </>
        ) : (
          <div style={{ flex: 1, backgroundColor: '#f8f9fa' }}>
            <DataConnections
              dataConnections={dataConnections}
              onDataConnectionsChange={setDataConnections}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
